import type { CareerQuestion } from "./rrt-questions";

export const otaQuestionsBatch5: CareerQuestion[] = [
  { id: "ota-1321", stem: "An OTA is educating a client with a new diagnosis of rheumatoid arthritis about joint protection. Which teaching method is MOST effective?", options: ["Verbal instruction only", "Demonstration with return demonstration, written handouts with pictures, and practice during functional activities", "Mailing a pamphlet after discharge", "Telling the family to teach the client"], correctIndex: 1, rationale: "Effective patient education combines multiple modalities: demonstration with return demonstration (skill verification), visual handouts, and practice in real functional contexts for transfer of learning.", difficulty: 1, category: "Patient Education", topic: "teaching methods" },
  { id: "ota-1322", stem: "When teaching a client about energy conservation, which principle should be emphasized FIRST?", options: ["Eliminate all activities", "Plan, prioritize, and pace activities throughout the day to manage fatigue", "Work as fast as possible to finish early", "Only rest in bed"], correctIndex: 1, rationale: "The '3 P's' of energy conservation: Plan (organize tasks), Prioritize (important tasks first), and Pace (alternate activity with rest). These fundamental principles apply to all diagnoses.", difficulty: 1, category: "Patient Education", topic: "energy conservation education" },
  { id: "ota-1323", stem: "A client is being taught a home exercise program (HEP). What is the MOST important factor for compliance?", options: ["Giving the most exercises possible", "Making the program simple, relevant to the client's goals, and integrated into daily routine", "Using complex medical terminology", "Requiring expensive equipment"], correctIndex: 1, rationale: "HEP compliance increases when exercises are simple, few in number, relevant to the client's goals, integrated into daily routines, and taught using teach-back demonstration.", difficulty: 1, category: "Patient Education", topic: "home program compliance" },
  { id: "ota-1324", stem: "Which learning style requires the OTA to use hands-on practice and physical manipulation during education?", options: ["Visual learner", "Auditory learner", "Kinesthetic learner", "Reading/writing learner"], correctIndex: 2, rationale: "Kinesthetic learners learn best through physical activity, hands-on practice, and direct experience. The OTA should provide opportunities to practice tasks and use movement-based learning.", difficulty: 1, category: "Patient Education", topic: "learning styles" },
  { id: "ota-1325", stem: "An OTA is teaching fall prevention to an elderly client. Which education point is MOST critical?", options: ["Fashion advice", "Remove throw rugs, improve lighting, use grab bars, wear proper footwear, and report dizziness or medication side effects", "How to call 911", "How to get up from the floor only"], correctIndex: 1, rationale: "Fall prevention education covers environmental modifications (rugs, lighting, grab bars), proper footwear, medication awareness, vision checks, and exercise for balance/strength.", difficulty: 1, category: "Patient Education", topic: "fall prevention education" },
  { id: "ota-1326", stem: "When educating a client with dementia, which strategy is MOST effective?", options: ["Long verbal lectures", "Simple, repetitive instructions using familiar cues and routines with caregiver involvement", "Written instructions only", "Complex problem-solving tasks"], correctIndex: 1, rationale: "Dementia education: short, simple, repetitive instructions using familiar cues, consistent routines, environmental cues, hands-on demonstration, and heavy caregiver involvement for reinforcement.", difficulty: 1, category: "Patient Education", topic: "dementia education strategies" },
  { id: "ota-1327", stem: "A client asks the OTA about their diagnosis and prognosis. What is the appropriate educational response?", options: ["Provide a detailed medical prognosis", "Educate about functional implications within OT scope, reinforce physician information, and direct medical questions to the physician", "Refuse to answer any questions", "Make up an answer"], correctIndex: 1, rationale: "The OTA can educate about functional implications, activity modifications, and reinforce physician-provided information. Medical diagnosis/prognosis questions should be directed to the physician.", difficulty: 1, category: "Patient Education", topic: "scope of education" },
  { id: "ota-1328", stem: "Which method verifies that a client understands the education provided?", options: ["Ask 'Do you understand?'", "Use the teach-back method: have the client demonstrate or explain the information in their own words", "Assume understanding if the client nods", "Give a written quiz"], correctIndex: 1, rationale: "Teach-back is the gold standard for verifying comprehension: the client explains or demonstrates the information back to the educator. Simple yes/no questions don't confirm understanding.", difficulty: 1, category: "Patient Education", topic: "comprehension verification" },
  { id: "ota-1329", stem: "An OTA is developing an ergonomic education program for an office worker with repetitive strain. What topics should be included?", options: ["Only chair height", "Workstation setup, neutral body positioning, microbreak schedule, stretching exercises, and proper mouse/keyboard technique", "Office decoration tips", "How to request a day off"], correctIndex: 1, rationale: "Ergonomic education covers workstation configuration, neutral postures, monitor positioning, keyboard/mouse technique, microbreaks every 30-60 minutes, and targeted stretching exercises.", difficulty: 1, category: "Patient Education", topic: "ergonomic education" },
  { id: "ota-1330", stem: "When teaching a client to use adaptive equipment, what is the recommended sequence?", options: ["Give the equipment and let them figure it out", "Explain the purpose, demonstrate proper use, have the client practice with feedback, then practice in the real task context", "Only provide written instructions", "Demonstrate once and move on"], correctIndex: 1, rationale: "Adaptive equipment training: explain purpose/benefit, demonstrate use, guided practice with feedback, independent practice, and finally practice in real task context for transfer of learning.", difficulty: 1, category: "Patient Education", topic: "equipment training sequence" },
  { id: "ota-1331", stem: "A client with diabetes needs education about skin care for neuropathic feet. What should the OTA teach?", options: ["Walk barefoot for exercise", "Inspect feet daily, wear properly fitting shoes, test water temperature with hands, moisturize (not between toes), and seek prompt wound care", "Ignore minor cuts", "Soak feet in hot water daily"], correctIndex: 1, rationale: "Diabetic foot care: daily inspection with mirror for hard-to-see areas, proper footwear, hand-testing water temperature, moisturizing skin (not between toes to prevent maceration), and prompt wound care.", difficulty: 1, category: "Patient Education", topic: "diabetes self-management" },
  { id: "ota-1332", stem: "Which educational strategy is BEST for teaching a visually impaired client to organize medications?", options: ["Color-coded labels only", "Tactile markers on containers, talking pill organizers, consistent spatial organization, and verbal repetition", "Tiny print labels", "No organization system needed"], correctIndex: 1, rationale: "Visual impairment medication management: tactile markers (rubber bands, Braille labels), talking devices, consistent spatial organization, auditory alarms, and large-print or high-contrast labels.", difficulty: 1, category: "Patient Education", topic: "visual impairment education" },
  { id: "ota-1333", stem: "An OTA is educating a caregiver on proper body mechanics for assisting transfers. What is the KEY point?", options: ["Bend at the waist", "Maintain wide base of support, bend knees, keep load close to body, avoid twisting, and use a gait belt", "Lift with the back", "Reach far away from the body"], correctIndex: 1, rationale: "Caregiver body mechanics: wide stance, bent knees (not waist), load close to body, avoid twisting, use leg muscles, maintain natural spinal curves, and always use a gait belt.", difficulty: 1, category: "Patient Education", topic: "caregiver body mechanics" },
  { id: "ota-1334", stem: "When developing a patient education handout, which design principle improves readability?", options: ["Dense text with small font", "Large font (14+ pt), simple language (6th grade reading level), pictures, white space, and bulleted lists", "Technical medical jargon", "Single-spaced paragraphs only"], correctIndex: 1, rationale: "Health literacy principles: large font, simple language (6th grade level), pictures/diagrams, adequate white space, bulleted lists, and key points highlighted.", difficulty: 1, category: "Patient Education", topic: "educational material design" },
  { id: "ota-1335", stem: "A client with COPD needs education on pursed-lip breathing. What instruction should the OTA provide?", options: ["Breathe in and out through the mouth rapidly", "Inhale slowly through the nose (2 counts), exhale slowly through pursed lips (4 counts) like blowing through a straw", "Hold breath for 30 seconds", "Breathe as fast as possible"], correctIndex: 1, rationale: "Pursed-lip breathing: inhale through nose (2 counts), exhale through pursed lips (4 counts) creating back-pressure that keeps airways open longer, improving gas exchange and reducing dyspnea.", difficulty: 1, category: "Patient Education", topic: "breathing techniques" },
  { id: "ota-1336", stem: "An 80-year-old client is being taught to use a new smartphone for medication reminders. What teaching approach is BEST?", options: ["Hand them the phone and let them explore", "Provide step-by-step instruction with large print guides, repeated practice sessions, and simplify the interface", "Use only verbal instructions over the phone", "Assume they cannot learn technology"], correctIndex: 1, rationale: "Technology education for older adults: step-by-step with repetition, large-print guides with screenshots, simplified interfaces, multiple practice sessions, and patient, non-judgmental teaching.", difficulty: 1, category: "Patient Education", topic: "technology education for elderly" },
  { id: "ota-1337", stem: "What is the primary goal of educating a client about work simplification techniques?", options: ["To make the client work faster", "To reduce physical demands of tasks by organizing work areas, eliminating unnecessary steps, and using efficient methods", "To reduce the number of tasks completed", "To avoid all work"], correctIndex: 1, rationale: "Work simplification reduces energy expenditure through efficient methods: organizing workspace, eliminating unnecessary steps, using labor-saving devices, and optimal body mechanics.", difficulty: 1, category: "Patient Education", topic: "work simplification" },
  { id: "ota-1338", stem: "An OTA is educating a client post-hip replacement about hip precautions. Which visual aid is MOST helpful?", options: ["Complex anatomy chart", "Simple diagrams showing prohibited positions (no flexion >90°, no adduction, no internal rotation) with daily activity examples", "No visual aids needed", "A video of hip surgery"], correctIndex: 1, rationale: "Simple diagrams with daily activity examples (bending to tie shoes = no, using long-handled shoe horn = yes) make abstract precautions concrete and improve adherence.", difficulty: 1, category: "Patient Education", topic: "precaution education" },
  { id: "ota-1339", stem: "When educating a client about pressure injury prevention, which key points should be included?", options: ["Only nutrition advice", "Weight shifts every 15-30 minutes, skin inspection, proper positioning, nutrition/hydration, cushion use, and avoiding moisture", "Change positions once daily", "Only use a pressure-relieving mattress"], correctIndex: 1, rationale: "Pressure injury prevention: regular weight shifts, daily skin inspection, proper positioning, adequate nutrition/hydration, appropriate cushions/mattresses, avoiding moisture/friction, and reporting skin changes.", difficulty: 1, category: "Patient Education", topic: "pressure injury prevention" },
  { id: "ota-1340", stem: "A client's family asks how to encourage participation in therapy at home. What education should the OTA provide?", options: ["Force the client to exercise", "Encourage structured routine, positive reinforcement, appropriate challenge level, and incorporation of therapy into meaningful daily activities", "Let the client rest completely", "Only exercise during professional therapy"], correctIndex: 1, rationale: "Home participation strategies: structured routines, positive reinforcement, appropriate challenge (not too easy or hard), meaningful activities, and patience with gradual progress.", difficulty: 1, category: "Patient Education", topic: "family engagement education" },
  { id: "ota-1341", stem: "An OTA is working with a 75-year-old client who reports increased falls at home. Which intervention addresses geriatric fall risk?", options: ["Bed rest to prevent falls", "Comprehensive fall prevention: environmental modifications, balance exercises, medication review referral, vision check, and assistive device assessment", "No intervention — falls are normal in aging", "Only a hip protector"], correctIndex: 1, rationale: "Geriatric fall prevention is multifactorial: environmental modifications (rugs, lighting, grab bars), exercise (balance, strength), medication review, vision/hearing checks, and assistive device assessment.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "fall prevention" },
  { id: "ota-1342", stem: "Which normal aging change most commonly affects hand function in elderly clients?", options: ["Improved fine motor skills", "Decreased grip strength, reduced joint flexibility, and decreased tactile sensitivity", "Increased muscle mass", "Faster reaction time"], correctIndex: 1, rationale: "Normal aging reduces grip strength (sarcopenia), joint flexibility (articular cartilage changes), tactile sensitivity (receptor loss), and visual acuity — all affecting hand function.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "normal aging changes" },
  { id: "ota-1343", stem: "A client with dementia at Allen Cognitive Level 4 can best perform which type of task?", options: ["Novel complex problem-solving", "Familiar routine tasks with visual cues and environmental structure", "Abstract reasoning activities", "Multi-step unfamiliar tasks"], correctIndex: 1, rationale: "ACL 4 (goal-directed actions) indicates the client can complete familiar, routine tasks using visual cues but cannot problem-solve novel situations or recognize errors. Structure and consistency are essential.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "dementia intervention" },
  { id: "ota-1344", stem: "An elderly client is socially isolated after the death of their spouse. Which OT intervention promotes psychosocial well-being?", options: ["No intervention needed", "Facilitate participation in meaningful activities, social groups, community programs, and meaningful occupations", "Prescribe antidepressants", "Suggest the client just needs time"], correctIndex: 1, rationale: "OT addresses social isolation through meaningful occupation: group activities, community program referrals, leisure exploration, volunteer opportunities, and facilitating social connections.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "psychosocial wellness" },
  { id: "ota-1345", stem: "A client in a skilled nursing facility needs to regain independence in bathing. What is the FIRST step?", options: ["Place the client in the shower immediately", "Assess current abilities, identify barriers, select appropriate adaptive equipment, and provide graded assistance during bathing", "Have staff continue to bathe the client", "Only sponge baths"], correctIndex: 1, rationale: "Bathing retraining starts with assessment of abilities and barriers, followed by equipment selection (tub bench, grab bars, handheld shower), graded assistance, and progressive independence.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "ADL retraining" },
  { id: "ota-1346", stem: "Which assessment is specifically designed to evaluate elderly clients' risk of falls?", options: ["MMSE", "Tinetti Performance-Oriented Mobility Assessment (POMA) or Timed Up and Go (TUG)", "Brunnstrom Stages", "Allen Cognitive Level Screen"], correctIndex: 1, rationale: "The Tinetti POMA assesses balance and gait. TUG measures time to stand, walk 3m, turn, and sit. Scores predict fall risk: TUG >12 seconds = increased fall risk.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "fall risk assessment" },
  { id: "ota-1347", stem: "An elderly client with osteoarthritis reports difficulty with meal preparation due to hand pain. What modifications should the OTA suggest?", options: ["Stop cooking entirely", "Lightweight utensils with built-up handles, electric can opener, pre-cut ingredients, jar opener, and pacing techniques", "Heavy cast-iron cookware", "Only eat cold meals"], correctIndex: 1, rationale: "Kitchen modifications for arthritis: lightweight tools, built-up/ergonomic handles, electric appliances, pre-prepared ingredients, anti-fatigue mats, and work simplification techniques.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "kitchen modification for arthritis" },
  { id: "ota-1348", stem: "What is sarcopenia and how does it affect elderly clients' occupational performance?", options: ["A skin condition", "Age-related loss of muscle mass and strength that reduces functional capacity for ADLs, mobility, and fall risk", "Hearing loss", "Vision changes"], correctIndex: 1, rationale: "Sarcopenia is age-related muscle loss (3-8% per decade after 30) reducing strength, endurance, and functional capacity. It increases fall risk and decreases ADL independence.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "geriatric conditions" },
  { id: "ota-1349", stem: "A client with mild cognitive impairment (MCI) is concerned about progressing to dementia. What cognitive strategies should the OTA teach?", options: ["Nothing can be done", "Cognitive engagement activities, external memory aids, physical exercise, social participation, and lifestyle modifications", "Isolation to reduce stress", "Only medication management"], correctIndex: 1, rationale: "MCI interventions include cognitive stimulation (puzzles, learning), external memory aids (calendars, lists), physical exercise, social engagement, healthy diet, and sleep hygiene.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "cognitive wellness" },
  { id: "ota-1350", stem: "An elderly client with diabetes and neuropathy needs foot care education during OT. What should be taught?", options: ["Walk barefoot for better proprioception", "Daily foot inspection, proper footwear, avoiding extreme temperatures, moisturizing, and reporting any skin changes", "Soak feet in hot water daily", "Cut toenails as short as possible"], correctIndex: 1, rationale: "Diabetic neuropathy foot care: daily inspection (mirror for soles), proper fitting shoes, avoid hot water (test with hands), moisturize (not between toes), and report any changes immediately.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "diabetic foot care" },
  { id: "ota-1351", stem: "Which approach is MOST effective for managing sundowning behavior in a client with dementia?", options: ["Increase stimulation in the evening", "Establish calming evening routines, reduce stimulation, ensure adequate lighting, and maintain consistent schedules", "Allow the client to wander freely", "Restrain the client"], correctIndex: 1, rationale: "Sundowning management: consistent evening routines, reduced stimulation, adequate lighting, calming activities, familiar environment, and avoiding caffeine/large meals late in the day.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "dementia behavioral management" },
  { id: "ota-1352", stem: "A geriatric client with decreased vision and hearing has difficulty with medication management. What is the OTA's role?", options: ["Administer medications", "Set up accessible medication systems (talking organizers, large-print labels, tactile cues) and train the client/caregiver", "Only refer to the pharmacist", "No role in medication management"], correctIndex: 1, rationale: "The OTA helps with medication management as an IADL: setting up accessible systems, training in use of adapted organizers, establishing routines, and involving caregivers as needed.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "IADL training" },
  { id: "ota-1353", stem: "What is delirium and how does it differ from dementia in elderly clients?", options: ["They are the same condition", "Delirium is acute/reversible with fluctuating consciousness; dementia is chronic/progressive with clear consciousness", "Delirium is always permanent", "Dementia always starts suddenly"], correctIndex: 1, rationale: "Delirium: acute onset, fluctuating consciousness, potentially reversible (infection, medication, dehydration). Dementia: gradual onset, progressive, clear consciousness (until late stages).", difficulty: 2, category: "Geriatric Rehabilitation", topic: "delirium vs dementia" },
  { id: "ota-1354", stem: "An 82-year-old client reports difficulty managing finances (paying bills, checkbook). This difficulty with IADLs may indicate:", options: ["Normal aging", "Possible cognitive decline requiring further assessment and compensatory strategies", "Laziness", "Poor education"], correctIndex: 1, rationale: "IADL difficulties (finances, medication management, meal prep) may be early indicators of cognitive decline. The OTA should report concerns to the OT for cognitive screening and implement compensatory strategies.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "cognitive screening" },
  { id: "ota-1355", stem: "Which leisure activity promotes cognitive engagement, social interaction, and fine motor skills in elderly clients?", options: ["Watching TV alone", "Card games, board games, or group crafts", "Sleeping", "Isolated reading only"], correctIndex: 1, rationale: "Card/board games and group crafts promote cognitive engagement (strategy, memory), social interaction (communication, turn-taking), and fine motor skills (card handling, craft manipulation).", difficulty: 1, category: "Geriatric Rehabilitation", topic: "leisure activities" },
  { id: "ota-1356", stem: "An elderly client in a nursing home has a pressure ulcer on the sacrum. What OT interventions can help?", options: ["No OT role in pressure ulcer management", "Wheelchair positioning assessment, pressure-relief cushion recommendation, positioning schedule, and activity programming to reduce time in bed", "Only wound dressing changes", "Keep the client in bed"], correctIndex: 1, rationale: "OT contributes to pressure ulcer management through wheelchair positioning, cushion selection, positioning schedules, weight-shift training, nutritional optimization, and reducing bed rest through activity.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "pressure ulcer management" },
  { id: "ota-1357", stem: "Which standardized assessment tool is commonly used to screen cognitive function in elderly clients?", options: ["Jamar dynamometer", "Mini-Mental State Examination (MMSE) or Montreal Cognitive Assessment (MoCA)", "Manual Muscle Test", "Goniometry"], correctIndex: 1, rationale: "MMSE and MoCA are brief cognitive screening tools assessing orientation, memory, attention, language, and visuospatial skills. They help identify cognitive impairment requiring further evaluation.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "cognitive assessment" },
  { id: "ota-1358", stem: "A client with osteoporosis and kyphosis needs education on safe body mechanics. What should the OTA emphasize?", options: ["Trunk flexion exercises are safe", "Maintain upright posture, avoid trunk flexion, use proper lifting mechanics, and perform standing extension exercises", "Heavy lifting is acceptable", "Sit in a slumped position"], correctIndex: 1, rationale: "Osteoporosis/kyphosis: maintain upright posture, avoid trunk flexion (compression fracture risk), use proper lifting mechanics, stand rather than bend, and perform extension exercises.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "osteoporosis management" },
  { id: "ota-1359", stem: "What is polypharmacy and why is it a concern in geriatric rehabilitation?", options: ["Taking one medication", "Taking multiple medications simultaneously, increasing risk of drug interactions, side effects, falls, and cognitive impairment", "Not taking any medications", "Taking medications on time"], correctIndex: 1, rationale: "Polypharmacy (5+ medications) increases drug interaction risk, side effects (drowsiness, dizziness), fall risk, and cognitive impairment in elderly clients, affecting rehab participation.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "medication concerns" },
  { id: "ota-1360", stem: "An elderly client with macular degeneration has difficulty reading. Which adaptation should the OTA recommend?", options: ["Stop reading entirely", "Large-print materials, magnification devices, high-contrast text, proper lighting, and audio alternatives", "Smaller text for practice", "Read in dim lighting"], correctIndex: 1, rationale: "Macular degeneration adaptations: large print, magnifiers (hand-held, electronic), high-contrast materials (black on white/yellow), task lighting, and audiobooks/text-to-speech technology.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "low vision adaptations" },
  { id: "ota-1361", stem: "At what age do children typically achieve independent hand-to-mouth feeding with a spoon?", options: ["6 months", "12-15 months", "24 months", "36 months"], correctIndex: 1, rationale: "Self-feeding with a spoon (messy) typically emerges at 12-15 months. By 18 months, children become more efficient. Full spoon proficiency develops by 2-3 years.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "developmental milestones" },
  { id: "ota-1362", stem: "A child with sensory processing disorder demonstrates gravitational insecurity. What does this mean?", options: ["Fear of heights only", "Excessive fear response to changes in head position or movement against gravity, especially when feet leave the ground", "Fear of insects", "Fear of water"], correctIndex: 1, rationale: "Gravitational insecurity is excessive fear of movement and position changes involving the head relative to gravity. Children resist being tilted, picked up, or having feet off the ground.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "sensory processing" },
  { id: "ota-1363", stem: "Which hand grasp pattern is expected to develop FIRST in infants?", options: ["Dynamic tripod grasp", "Palmar grasp (reflexive, then voluntary)", "Pincer grasp", "Lateral pinch"], correctIndex: 1, rationale: "Grasp development: reflexive palmar grasp (birth), voluntary palmar grasp (3-4mo), raking (6mo), radial-digital (7-8mo), pincer (9-10mo), and tripod grasp (3.5-4yr).", difficulty: 1, category: "Pediatric Rehabilitation", topic: "grasp development" },
  { id: "ota-1364", stem: "An OTA is implementing a sensory diet for a child with autism spectrum disorder. What should the diet include?", options: ["Only food-related activities", "Individualized sensory activities scheduled throughout the day based on the child's specific sensory needs and responses", "Random sensory activities", "Eliminating all sensory input"], correctIndex: 1, rationale: "A sensory diet is an individualized plan of sensory-based activities (proprioceptive, vestibular, tactile) scheduled throughout the day to maintain optimal arousal for participation.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "sensory diet" },
  { id: "ota-1365", stem: "At what age should a child typically be able to copy a circle?", options: ["18 months", "3 years", "5 years", "7 years"], correctIndex: 1, rationale: "Pre-writing development: imitates vertical line (2yr), copies circle (3yr), copies cross (4yr), copies square (4.5yr), copies triangle (5yr), copies diamond (6-7yr).", difficulty: 1, category: "Pediatric Rehabilitation", topic: "pre-writing skills" },
  { id: "ota-1366", stem: "A child with cerebral palsy has increased tone in the upper extremities. Which intervention helps reduce spasticity before functional activities?", options: ["Quick stretching", "Slow sustained stretching, weight-bearing through the affected arm, and rhythmic rotation", "Rapid alternating movements", "Resistance training"], correctIndex: 1, rationale: "Spasticity is reduced by slow sustained stretching (not quick stretch which increases tone), prolonged weight-bearing, rhythmic rotation, and neutral warmth before functional activities.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "tone management" },
  { id: "ota-1367", stem: "Which play stage involves children playing alongside each other but not together (ages 2-3)?", options: ["Solitary play", "Parallel play", "Cooperative play", "Associative play"], correctIndex: 1, rationale: "Parallel play (2-3 years): children play near each other with similar materials but do not directly interact or share. Cooperative play with shared goals develops around 4-5 years.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "play development" },
  { id: "ota-1368", stem: "An OTA is working with a child who has visual-motor integration difficulties. Which activity addresses this deficit?", options: ["Auditory discrimination tasks", "Bead stringing, cutting on lines, tracing, and copying geometric shapes", "Language drills", "Gross motor running activities"], correctIndex: 1, rationale: "Visual-motor integration activities coordinate visual perception with motor output: bead stringing, cutting on lines, tracing, copying shapes, mazes, and connecting dots.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "visual-motor integration" },
  { id: "ota-1369", stem: "A child with autism refuses to wear certain fabrics and avoids light touch. Which sensory system is likely affected?", options: ["Vestibular", "Proprioceptive", "Tactile (tactile defensiveness/hypersensitivity)", "Auditory"], correctIndex: 2, rationale: "Tactile defensiveness/hypersensitivity causes adverse reactions to certain textures, light touch, and clothing labels/seams. Treatment uses graded tactile exposure in child-directed play.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "tactile processing" },
  { id: "ota-1370", stem: "Which developmental milestone is expected by age 6 months?", options: ["Walking independently", "Sitting with support and beginning to reach and grasp objects voluntarily", "Running", "Cutting with scissors"], correctIndex: 1, rationale: "By 6 months: sits with support, begins voluntary reaching/grasping, transfers objects hand-to-hand, and brings objects to mouth for oral exploration.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "motor milestones" },
  { id: "ota-1371", stem: "A child with Down syndrome has difficulty with dressing due to hypotonia. Which strategy helps?", options: ["Dress the child quickly to save time", "Provide extra trunk support, use clothing with elastic waists, practice in supportive positioning, and allow extra time", "Only use button-front shirts", "Avoid dressing practice"], correctIndex: 1, rationale: "Hypotonia strategies for dressing: supportive positioning (seated against wall/corner), easy-on clothing (elastic waists, slip-on shoes), backward chaining for success, and extra time.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "dressing with hypotonia" },
  { id: "ota-1372", stem: "At what age should a child typically be able to tie shoelaces?", options: ["3 years", "4 years", "6-7 years", "10 years"], correctIndex: 2, rationale: "Shoe-tying is a complex bilateral fine motor task typically mastered at 6-7 years. It requires finger dexterity, bilateral coordination, motor planning, and visual-motor integration.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "self-care milestones" },
  { id: "ota-1373", stem: "Which feeding position is recommended for an infant with poor head control?", options: ["Fully reclined at 180°", "Semi-reclined (45°) with head and trunk support, chin slightly tucked", "Fully upright at 90° without support", "Prone position"], correctIndex: 1, rationale: "Semi-reclined position with head/trunk support promotes safe feeding for infants with poor head control. Chin tuck helps protect the airway. Avoid fully reclined (aspiration risk).", difficulty: 2, category: "Pediatric Rehabilitation", topic: "feeding positioning" },
  { id: "ota-1374", stem: "An OTA is working with a 7-year-old child with developmental coordination disorder (DCD). Which occupational challenge is MOST common?", options: ["Behavior problems only", "Handwriting difficulties, difficulty with self-care tasks, poor ball skills, and challenges with academic performance", "Only social difficulties", "Language delays"], correctIndex: 1, rationale: "DCD affects motor coordination impacting handwriting, self-care (buttons, zippers), ball skills (catching, throwing), bike riding, and academic tasks requiring motor output.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "developmental coordination disorder" },
  { id: "ota-1375", stem: "Which approach uses play as the primary intervention medium in pediatric OT?", options: ["Biomechanical approach", "Cognitive-behavioral approach", "Play-based intervention within a sensory integration framework", "Adult rehabilitation approach"], correctIndex: 2, rationale: "Play-based intervention uses the child's intrinsic motivation for play to address sensory processing, motor skills, and functional development within the context of meaningful play activities.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "play-based intervention" },
  { id: "ota-1376", stem: "A child with spastic diplegic cerebral palsy GMFCS Level IV needs a seating system. What is the primary goal?", options: ["Comfort only", "Provide postural support for functional upper extremity use, positioning for social interaction, and pressure distribution", "Make the child stand", "Reduce the wheelchair cost"], correctIndex: 1, rationale: "GMFCS Level IV children use wheeled mobility. Seating goals: optimal postural alignment, UE function facilitation, pressure distribution, social positioning, and respiratory support.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "pediatric seating" },
  { id: "ota-1377", stem: "Which handwriting curriculum is commonly used in pediatric OT to address letter formation?", options: ["Adult cursive program", "Handwriting Without Tears (Learning Without Tears)", "Speed writing course", "No structured program exists"], correctIndex: 1, rationale: "Handwriting Without Tears uses a multisensory, developmental approach with wood pieces, wet-dry-try chalkboard method, and consistent letter formation sequence. It addresses readiness through foundational skills.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "handwriting intervention" },
  { id: "ota-1378", stem: "An infant born at 28 weeks gestation needs developmental monitoring. When calculating developmental milestones, the OTA should use:", options: ["Chronological age", "Corrected (adjusted) age until the child is 2-3 years old", "Neither chronological nor corrected age", "The age at which siblings achieved milestones"], correctIndex: 1, rationale: "Premature infants use corrected age (chronological age minus weeks premature) for developmental milestone assessment until 2-3 years, when most premature children catch up to peers.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "prematurity" },
  { id: "ota-1379", stem: "What is the primary role of OT in the NICU (neonatal intensive care unit)?", options: ["Only feeding assessment", "Developmentally supportive positioning, sensory environment modification, parent education, and feeding support", "No OT role in NICU", "Only social services referral"], correctIndex: 1, rationale: "NICU OT: developmental positioning, minimizing noxious sensory input, supporting state regulation, parent-infant bonding, feeding readiness assessment, and parent education.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "NICU intervention" },
  { id: "ota-1380", stem: "A school-aged child with ADHD has difficulty staying seated and focused during classroom activities. Which OT strategy helps?", options: ["Punish the child for moving", "Provide movement breaks, fidget tools, alternative seating (therapy ball, wobble cushion), and structured environment", "Eliminate all physical activity", "Only medication management"], correctIndex: 1, rationale: "ADHD classroom strategies: scheduled movement breaks, fidget tools, alternative seating providing movement input, structured environment, visual schedules, and sensory strategies.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "ADHD management" },
  { id: "ota-1381", stem: "A client with left hemisphere stroke presents with right hemiplegia and Broca's aphasia. Which OT approach addresses the aphasia component?", options: ["Ignore communication difficulties", "Use simple yes/no questions, visual cues, allow extra response time, and collaborate with SLP for consistent communication strategies", "Speak rapidly to save time", "Only work on motor recovery"], correctIndex: 1, rationale: "Broca's aphasia: comprehension relatively intact but expression impaired. Use yes/no questions, allow time, provide visual choices, be patient, and coordinate with SLP.", difficulty: 2, category: "Neurological Rehabilitation", topic: "aphasia management" },
  { id: "ota-1382", stem: "A client with a complete C5 SCI is working on self-feeding. Which technique and equipment enable independent feeding?", options: ["Standard utensils only", "Universal cuff with adapted utensils, mobile arm support (MAS), plate guard, and non-slip mat", "No adaptive equipment available", "Only tube feeding"], correctIndex: 1, rationale: "C5 SCI feeding: universal cuff (straps utensil to hand), MAS (supports arm weight), plate guard (prevents food spillage), non-slip mat, and built-up utensils.", difficulty: 2, category: "Neurological Rehabilitation", topic: "SCI self-feeding" },
  { id: "ota-1383", stem: "Which intervention technique uses mental practice of movement to improve motor recovery after stroke?", options: ["Passive ROM", "Mental imagery/motor imagery where the client imagines performing a movement", "Only physical practice", "Relaxation only"], correctIndex: 1, rationale: "Motor imagery involves mentally rehearsing movement without physical execution. It activates similar brain regions as actual movement and can enhance motor recovery when combined with physical practice.", difficulty: 2, category: "Neurological Rehabilitation", topic: "motor imagery" },
  { id: "ota-1384", stem: "A client with TBI demonstrates poor safety awareness — reaching for hot surfaces, leaving stove on. Which cognitive deficit is primarily involved?", options: ["Memory", "Executive function (judgment, safety awareness, problem-solving)", "Language", "Visual perception"], correctIndex: 1, rationale: "Executive function deficits impair judgment, risk assessment, and safety awareness. TBI clients may lack insight into their deficits (anosognosia) requiring environmental modifications and supervision.", difficulty: 2, category: "Neurological Rehabilitation", topic: "executive function deficits" },
  { id: "ota-1385", stem: "A client with Parkinson's disease has micrographia. Which compensatory strategy helps improve handwriting legibility?", options: ["Write faster", "Use wide-ruled paper, thick-barreled pen, large deliberate letter formation, and write with arm movement rather than finger movement", "Use a thinner pen", "Only type — never handwrite"], correctIndex: 1, rationale: "Micrographia compensation: wide-ruled paper, thick pen/pencil, deliberately large letters, visual targets for letter size, and using arm/shoulder movement rather than finger-only movement.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Parkinson's handwriting" },
  { id: "ota-1386", stem: "Which type of visual field deficit is most commonly associated with stroke and affects the same side of both eyes?", options: ["Monocular blindness", "Homonymous hemianopia", "Tunnel vision", "Central scotoma"], correctIndex: 1, rationale: "Homonymous hemianopia (loss of the same half of the visual field in both eyes) is the most common visual field deficit after stroke, caused by damage to the optic radiations or occipital cortex.", difficulty: 2, category: "Neurological Rehabilitation", topic: "visual field deficits" },
  { id: "ota-1387", stem: "A client with MS reports numbness and tingling in both hands affecting functional activities. Which type of MS symptom is this?", options: ["Motor symptom", "Sensory symptom (paresthesia)", "Cognitive symptom", "Emotional symptom"], correctIndex: 1, rationale: "Paresthesia (numbness, tingling) is a common sensory symptom of MS caused by demyelination of sensory nerve fibers. It affects fine motor function and safety (impaired protective sensation).", difficulty: 1, category: "Neurological Rehabilitation", topic: "MS symptoms" },
  { id: "ota-1388", stem: "A client with a SCI at T6 has autonomic dysreflexia during OT. After sitting the client upright, what should the OTA check FIRST?", options: ["Blood glucose level", "Urinary catheter for kinks or blockage (most common trigger)", "Blood type", "Cognitive status"], correctIndex: 1, rationale: "The most common trigger for autonomic dysreflexia is bladder distension (kinked or blocked catheter). After positioning upright, check catheter first, then bowel, tight clothing, and skin issues.", difficulty: 2, category: "Neurological Rehabilitation", topic: "autonomic dysreflexia management" },
  { id: "ota-1389", stem: "A client with right hemisphere stroke has difficulty recognizing familiar faces. This condition is called:", options: ["Aphasia", "Prosopagnosia (face blindness)", "Neglect", "Ataxia"], correctIndex: 1, rationale: "Prosopagnosia is the inability to recognize familiar faces, typically associated with right hemisphere lesions. Clients may need to use other cues (voice, clothing, context) for recognition.", difficulty: 3, category: "Neurological Rehabilitation", topic: "agnosia" },
  { id: "ota-1390", stem: "Which neurological technique involves repetitive, task-specific practice to promote neuroplasticity?", options: ["Passive ROM only", "Task-specific training based on motor learning principles and repetitive practice", "Complete bed rest", "Massage only"], correctIndex: 1, rationale: "Task-specific training uses repetitive, meaningful, goal-directed practice to drive neuroplasticity. Evidence shows the brain reorganizes in response to intensive, specific motor practice.", difficulty: 2, category: "Neurological Rehabilitation", topic: "neuroplasticity" },
  { id: "ota-1391", stem: "A client with a peripheral nerve injury at the wrist has weakness in thumb opposition. Which nerve is likely affected?", options: ["Radial nerve", "Ulnar nerve", "Median nerve (recurrent motor branch)", "Musculocutaneous nerve"], correctIndex: 2, rationale: "The recurrent motor branch of the median nerve innervates the thenar muscles (opponens pollicis, abductor pollicis brevis). Injury causes weakness in thumb opposition affecting pinch and grasp.", difficulty: 2, category: "Neurological Rehabilitation", topic: "peripheral nerve injury" },
  { id: "ota-1392", stem: "A client post-stroke is working on bilateral UE activities. Which type of task promotes bilateral coordination?", options: ["Unilateral sanding board", "Bilateral activities such as towel wringing, jar opening, and cutting with knife and fork", "Single-arm reaching only", "Passive range of motion"], correctIndex: 1, rationale: "Bilateral activities (towel wringing, jar opening, cutting food) require coordinated use of both hands in complementary roles, promoting bilateral integration and hemiplegic arm activation.", difficulty: 1, category: "Neurological Rehabilitation", topic: "bilateral coordination training" },
  { id: "ota-1393", stem: "What is the primary goal of mirror therapy for a client with upper extremity hemiplegia post-stroke?", options: ["To reflect sunlight for warmth", "To create a visual illusion of bilateral movement, activating motor areas for the affected limb", "To check personal appearance", "To improve visual acuity"], correctIndex: 1, rationale: "Mirror therapy places a mirror at the midline reflecting the unaffected arm's movement, creating a visual illusion of bilateral symmetrical movement that activates motor cortex for the affected side.", difficulty: 2, category: "Neurological Rehabilitation", topic: "mirror therapy" },
  { id: "ota-1394", stem: "A client with a cerebellar lesion demonstrates dysmetria. What does this mean for functional activities?", options: ["They can perform activities normally", "They overshoot or undershoot when reaching for objects, making accurate movement difficult", "They have paralysis", "They have sensory loss"], correctIndex: 1, rationale: "Dysmetria is the inability to accurately judge distance during reaching, causing overshooting (hypermetria) or undershooting (hypometria). It impairs functional tasks requiring accuracy.", difficulty: 2, category: "Neurological Rehabilitation", topic: "cerebellar deficits" },
  { id: "ota-1395", stem: "A client with Guillain-Barré syndrome is in the recovery phase. What is the primary OT focus?", options: ["Aggressive strengthening immediately", "Gradual strengthening, endurance building, and ADL retraining as motor function returns from proximal to distal", "Only passive ROM", "No treatment until fully recovered"], correctIndex: 1, rationale: "GBS recovery is proximal to distal. OT focuses on gradual strengthening (avoiding overwork damage), endurance building, and progressive ADL retraining as function returns.", difficulty: 2, category: "Neurological Rehabilitation", topic: "GBS rehabilitation" },
  { id: "ota-1396", stem: "A client post ACL reconstruction at 4 weeks is doing well with knee rehabilitation. The OTA is working on functional activities. Which OT goal is appropriate?", options: ["Full return to sports", "Safe bathroom transfers, car transfers with knee precautions, and modified household tasks within weight-bearing restrictions", "No OT involvement needed", "Running activities"], correctIndex: 1, rationale: "At 4 weeks post-ACL, OT focuses on functional activities within weight-bearing restrictions: safe transfers, modified household tasks, and ADL strategies while following surgeon protocols.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "ACL rehabilitation" },
  { id: "ota-1397", stem: "A client is 8 weeks post-total shoulder arthroplasty. Which activities are appropriate for the OTA to practice?", options: ["Overhead lifting with heavy weights", "Light functional activities at and below shoulder height: grooming, tabletop tasks, and light meal preparation", "Throwing a ball", "Vigorous shoulder flexion past 120°"], correctIndex: 1, rationale: "At 8 weeks post-TSA, light functional activities at and below shoulder height are appropriate. Follow surgeon-specific protocols for ROM limits and weight restrictions.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "shoulder arthroplasty rehabilitation" },
  { id: "ota-1398", stem: "A client with a distal radius fracture is in the sub-acute phase (4-8 weeks). What OT interventions are appropriate?", options: ["Aggressive passive stretching", "Active ROM exercises, gentle strengthening, scar management (if surgical), edema control, and functional activities", "No treatment until 12 weeks", "Heavy resistance training"], correctIndex: 1, rationale: "Sub-acute distal radius fracture: AROM exercises, gentle progressive strengthening, scar massage (if post-surgical), edema management, and functional activity training.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "distal radius fracture" },
  { id: "ota-1399", stem: "A client has a rotator cuff tear that is being managed conservatively (non-surgical). What is the OT role?", options: ["No OT involvement", "Pain management, gentle ROM maintenance, activity modification, ergonomic education, and gradual functional return", "Aggressive strengthening immediately", "Only ice application"], correctIndex: 1, rationale: "Conservative rotator cuff management: pain modalities, gentle AROM/PROM, activity modification (avoiding overhead activities), ergonomic education, and gradual return to function.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "rotator cuff management" },
  { id: "ota-1400", stem: "A client post-total knee replacement has difficulty getting in and out of a car. What adaptive strategy should the OTA teach?", options: ["Avoid all car travel", "Back up to the car seat, sit first, then swing legs in using a plastic bag on the seat to reduce friction", "Jump into the car", "Climb over the console"], correctIndex: 1, rationale: "Car transfer post-TKR: back up to the seat, sit on a plastic bag (reduces friction), lean back, swing legs in. Reverse for exit. Passenger seat provides more room.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "car transfers" },
  { id: "ota-1401", stem: "A client with a humeral fracture is immobilized in a shoulder immobilizer. Which adjacent joints should be exercised?", options: ["No joints should be exercised", "Elbow, wrist, and hand — maintain ROM in joints not immobilized", "Only the shoulder", "Only the opposite arm"], correctIndex: 1, rationale: "During immobilization, exercise adjacent free joints (elbow, wrist, fingers) to prevent stiffness, maintain circulation, and reduce edema. Finger pumping also aids venous return.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "immobilization management" },
  { id: "ota-1402", stem: "A client with a flexor tendon repair at 3 weeks post-surgery reports hearing a 'pop' in the finger followed by inability to flex the finger. What likely occurred?", options: ["Normal healing", "Tendon re-rupture — stop all exercise and notify the surgeon immediately", "Tendon adhesion", "Joint subluxation"], correctIndex: 1, rationale: "A 'pop' with sudden loss of flexion strongly suggests tendon re-rupture. This is a surgical emergency. Stop all exercise, splint in protective position, and notify the surgeon immediately.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "tendon repair complications" },
  { id: "ota-1403", stem: "What is the primary advantage of early controlled motion protocols after flexor tendon repair compared to immobilization?", options: ["Faster return to work", "Reduced adhesion formation, improved tendon strength, and better functional outcomes", "Less pain", "Lower cost"], correctIndex: 1, rationale: "Early controlled motion protocols reduce adhesion formation through controlled tendon gliding, promote intrinsic tendon healing, increase tensile strength, and produce superior functional outcomes.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "tendon repair protocols" },
  { id: "ota-1404", stem: "A client with lateral epicondylitis is returning to tennis. What ergonomic modifications should the OTA recommend?", options: ["Play through the pain", "Use a larger grip size, counterforce brace, reduce string tension, ensure proper backhand technique, and warm up before play", "Use a heavier racket", "Stop playing tennis permanently"], correctIndex: 1, rationale: "Tennis modifications for lateral epicondylitis: larger grip size (reduces gripping force), counterforce brace, lower string tension, two-handed backhand technique, and adequate warm-up.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "sports injury modification" },
  { id: "ota-1405", stem: "A client is 6 months post-total hip replacement with no complications. Are there still precautions?", options: ["Strict lifetime precautions", "Most surgeon-specific precautions are lifted by 3-6 months; activities can progressively normalize while avoiding extreme positions and high-impact activities", "No precautions were ever needed", "Same precautions as day 1"], correctIndex: 1, rationale: "By 6 months post-THR, most precautions are lifted as soft tissue heals. Avoid high-impact activities and extreme positions but gradually return to normal activities per surgeon guidance.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "long-term joint replacement" },
  { id: "ota-1406", stem: "A client with a scaphoid fracture is immobilized in a thumb spica cast. How long is typical immobilization?", options: ["1-2 weeks", "6-12 weeks due to poor scaphoid blood supply", "24 hours", "6 months"], correctIndex: 1, rationale: "Scaphoid fractures require 6-12 weeks immobilization due to retrograde blood supply that makes healing slow. Non-union and avascular necrosis are risks if inadequately immobilized.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "scaphoid fracture management" },
  { id: "ota-1407", stem: "A client post-ORIF of the olecranon is cleared for AROM at 4 weeks. What exercise should the OTA start with?", options: ["Resistive triceps strengthening", "Gentle active elbow flexion/extension within pain-free range, forearm rotation, and wrist ROM", "Passive manipulation of the elbow", "Heavy lifting immediately"], correctIndex: 1, rationale: "Early AROM post-olecranon ORIF: gentle active flexion/extension within pain-free range, forearm pronation/supination, and wrist exercises. Progress resistance later per surgeon protocol.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "elbow fracture rehabilitation" },
  { id: "ota-1408", stem: "A client with adhesive capsulitis is in the 'frozen' (adhesive) phase. What is the primary OT goal?", options: ["Restore full ROM immediately", "Maintain available ROM, manage pain, and modify activities while awaiting resolution of the adhesive phase", "Aggressive passive stretching", "No intervention during this phase"], correctIndex: 1, rationale: "The frozen phase is characterized by significant stiffness with less pain. Goals: maintain available ROM through gentle exercise, manage residual pain, and modify activities to maintain function.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "adhesive capsulitis management" },
  { id: "ota-1409", stem: "A client with a boxer's fracture (5th metacarpal neck) has been immobilized for 4 weeks. What is the first OT intervention after cast removal?", options: ["Heavy grip strengthening", "Gentle AROM of MCP, PIP, and DIP joints, edema management, and scar massage if surgical", "Aggressive PROM immediately", "Return to boxing"], correctIndex: 1, rationale: "After 4 weeks immobilization: gentle AROM of finger joints, edema management (elevation, retrograde massage), scar care if surgical, and gradual functional activity retraining.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "metacarpal fracture rehabilitation" },
  { id: "ota-1410", stem: "What is the primary concern when a client reports numbness and tingling after cast application?", options: ["Normal after casting", "Possible compartment syndrome or nerve compression — report immediately for cast evaluation", "Wait and see for 24 hours", "Apply heat to the cast"], correctIndex: 1, rationale: "Numbness/tingling after casting may indicate compartment syndrome or nerve compression. This is a medical emergency requiring immediate cast evaluation and possible windowing/removal.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "cast complications" },
  { id: "ota-1411", stem: "A client recovering from bilateral wrist fractures needs to feed independently during healing. Which adaptation is MOST appropriate?", options: ["No adaptations possible", "Wrist-free adaptive utensils with swivel feature, plate guards, non-slip mats, and cup with lid and straw", "Standard utensils only", "Only tube feeding"], correctIndex: 1, rationale: "Bilateral wrist fracture adaptations: utensils with universal cuffs or arm-mounted holders (bypassing wrist motion), swivel utensils, plate guards, non-slip surfaces, and adapted cups.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "bilateral fracture adaptations" },
  { id: "ota-1412", stem: "A client is 12 weeks post-flexor tendon repair and is cleared for resistive exercise. What should the OTA start with?", options: ["Maximum grip strengthening immediately", "Light resistance activities: soft theraputty, light functional tasks progressing gradually to heavier resistance", "No resistive exercise ever", "Heavy weightlifting"], correctIndex: 1, rationale: "At 12 weeks, the tendon has sufficient strength for light resistance. Start with soft putty, light functional tasks, and progress gradually. Monitor for increased pain or loss of ROM.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "tendon repair strengthening" },
  { id: "ota-1413", stem: "A client with a stable pelvic fracture needs ADL training. Which precautions apply?", options: ["No precautions", "Weight-bearing restrictions per physician, log-roll for bed mobility, avoid hip flexion past prescribed limits, and pain-guided activity", "Full activity immediately", "Only bed rest for 3 months"], correctIndex: 1, rationale: "Stable pelvic fracture: follow WB restrictions, log-roll technique, avoid excessive hip flexion/rotation, pain-guided activity progression, and adaptive equipment for ADL independence.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "pelvic fracture management" },
  { id: "ota-1414", stem: "A client with a clavicle fracture is wearing a figure-of-eight strap. What adjacent joint exercises should be prescribed?", options: ["No exercises", "Elbow ROM, wrist ROM, grip exercises, and gentle pendulum exercises when physician-approved", "Full shoulder ROM immediately", "Heavy lifting"], correctIndex: 1, rationale: "During clavicle fracture immobilization: maintain elbow, wrist, and hand ROM. Gentle pendulum exercises may be started when approved. Avoid shoulder abduction and flexion until cleared.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "clavicle fracture management" },
  { id: "ota-1415", stem: "A client post-wrist arthroscopy has pain and swelling. What is the initial OT focus?", options: ["Aggressive strengthening", "Edema management, pain control, gentle AROM, wound care, and gradual return to function", "No treatment needed", "Only ice"], correctIndex: 1, rationale: "Post-arthroscopy: edema management (elevation, compression, gentle pumping), pain control, gentle AROM as tolerated, wound care, and progressive functional activity.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "post-arthroscopy rehabilitation" },
];
